def test_phase20_release_handoff_manifest_validator_accepts_phase43_handoff_and_rejects_boundary_break(
    tmp_path,
):
    manifest_path = "docs/specs/hermes_decisiondoc_agent/phase20_release_handoff/handoff_manifest.json"
    validator = "scripts/validate_phase20_release_handoff_manifest.py"

    valid = subprocess.run(
        ["python3", validator, manifest_path],
        capture_output=True,
        check=False,
        text=True,
    )

    assert valid.returncode == 0
    assert "PASS phase20 release handoff manifest validated" in valid.stdout
    assert "release_handoff_valid=true" in valid.stdout
    assert "phase43_handoff_included=true" in valid.stdout
    assert "local_export_openability_validated=true" in valid.stdout
    assert "aws_cost_boundary=no_cost_increase" in valid.stdout
    assert "training_boundary=not_authorized" in valid.stdout

    broken_payload = json.load(open(manifest_path, encoding="utf-8"))
    broken_payload["phase_coverage"]["phase43"]["aws_runtime_called"] = True
    broken_path = tmp_path / "broken_phase20_handoff_manifest.json"
    broken_path.write_text(json.dumps(broken_payload, ensure_ascii=False, indent=2), encoding="utf-8")
    broken = subprocess.run(
        ["python3", validator, str(broken_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert broken.returncode == 1
    assert "FAIL phase20 release handoff manifest validation failed" in broken.stdout
    assert "phase_coverage.phase43.aws_runtime_called must be false" in broken.stdout
    assert (
        "phase20_release_handoff_manifest: $.phase_coverage.phase43.aws_runtime_called must be false"
        in broken.stdout
    )


