def test_phase60_local_feature_completion_validated_closure_handoff_signoff_summary_reports_pending_completed_and_boundary_breaks(
    tmp_path,
):
    generator = (
        "scripts/create_documentops_local_feature_completion_validated_closure_handoff_pending_signoff.py"
    )
    reporter = "scripts/summarize_documentops_local_feature_completion_validated_closure_handoff_signoffs.py"
    pending_path = tmp_path / "phase60_pending_signoff.json"
    summary_path = tmp_path / "phase60_signoff_summary.json"
    markdown_path = tmp_path / "phase60_signoff_summary.md"

    generated = subprocess.run(
        [
            "python3",
            generator,
            "--output",
            str(pending_path),
            "--signoff-id",
            "documentops_local_feature_completion_validated_closure_handoff_signoff_phase60pending",
            "--created-at",
            "2026-05-27T00:00:00+09:00",
        ],
        capture_output=True,
        check=False,
        text=True,
    )

    assert generated.returncode == 0
    assert pending_path.exists()

    pending_summary = subprocess.run(
        [
            "python3",
            reporter,
            str(pending_path),
            "--generated-at",
            "2026-05-27T00:00:00+09:00",
            "--output",
            str(summary_path),
            "--markdown-output",
            str(markdown_path),
        ],
        capture_output=True,
        check=False,
        text=True,
    )

    assert pending_summary.returncode == 0
    pending_summary_payload = json.loads(pending_summary.stdout)
    assert pending_summary_payload["report_type"] == (
        "document_ops_phase60_local_feature_completion_validated_closure_handoff_signoff_summary"
    )
    assert pending_summary_payload["ok"] is True
    assert pending_summary_payload["completion_ready"] is False
    assert pending_summary_payload["readiness"]["status"] == (
        "pending_validated_closure_handoff_signoff_review_no_training_authorization"
    )
    assert pending_summary_payload["counts"]["signoff_count"] == 1
    assert pending_summary_payload["counts"]["valid_signoff_count"] == 1
    assert pending_summary_payload["counts"]["pending_signoff_count"] == 1
    assert pending_summary_payload["counts"]["completed_signoff_count"] == 0
    assert pending_summary_payload["counts"]["boundary_break_count"] == 0
    assert pending_summary_payload["side_effect_boundary"]["service_resume_authorized"] is False
    assert pending_summary_payload["side_effect_boundary"]["training_execution_started"] is False
    assert summary_path.exists()
    assert markdown_path.exists()
    assert "pending_validated_closure_handoff_signoff_review_no_training_authorization" in markdown_path.read_text(
        encoding="utf-8"
    )

    pending_require_complete = subprocess.run(
        ["python3", reporter, str(pending_path), "--require-complete"],
        capture_output=True,
        check=False,
        text=True,
    )

    assert pending_require_complete.returncode == 1
    pending_require_complete_payload = json.loads(pending_require_complete.stdout)
    assert pending_require_complete_payload["ok"] is False
    assert "completed_accepted_signoffs_required" in pending_require_complete_payload["readiness"][
        "blocker_reasons"
    ]

    completed_payload = json.load(open(pending_path, encoding="utf-8"))
    completed_payload["signoff_id"] = (
        "documentops_local_feature_completion_validated_closure_handoff_signoff_phase60done"
    )
    completed_payload["decision"] = "accepted"
    completed_payload["reviewer"] = {
        "name": "Phase 60 Reviewer",
        "title_or_team": "Release Review",
        "reviewed_at": "2026-05-27T00:00:00+09:00",
    }
    completed_payload["evidence_reviewed"] = [
        "docs/specs/hermes_decisiondoc_agent/phase57_local_feature_completion_validated_closure_handoff/validated_closure_handoff.json",
        "docs/specs/hermes_decisiondoc_agent/phase58_local_feature_completion_validated_closure_handoff_signoff/validated_closure_handoff_signoff_template.json",
    ]
    completed_payload["findings"]["summary"] = (
        "Phase 57 validated closure handoff sign-off evidence accepted without operation authorization."
    )
    for key in completed_payload["acknowledgements"]:
        completed_payload["acknowledgements"][key] = True
    completed_path = tmp_path / "phase60_completed_signoff.json"
    completed_path.write_text(json.dumps(completed_payload, ensure_ascii=False, indent=2), encoding="utf-8")
    completed_summary = subprocess.run(
        [
            "python3",
            reporter,
            str(completed_path),
            "--generated-at",
            "2026-05-27T00:00:00+09:00",
            "--require-complete",
        ],
        capture_output=True,
        check=False,
        text=True,
    )

    assert completed_summary.returncode == 0
    completed_summary_payload = json.loads(completed_summary.stdout)
    assert completed_summary_payload["ok"] is True
    assert completed_summary_payload["completion_ready"] is True
    assert completed_summary_payload["readiness"]["status"] == (
        "all_validated_closure_handoff_signoffs_accepted_no_cost_boundary_preserved"
    )
    assert completed_summary_payload["counts"]["completed_signoff_count"] == 1
    assert completed_summary_payload["counts"]["accepted_signoff_count"] == 1
    assert completed_summary_payload["signoffs"][0]["validation"]["source_handoff_validation_ok"] is True

    broken_payload = json.loads(json.dumps(completed_payload))
    broken_payload["signoff_boundary"]["training_execution_authorized"] = True
    broken_path = tmp_path / "phase60_broken_training_signoff.json"
    broken_path.write_text(json.dumps(broken_payload, ensure_ascii=False, indent=2), encoding="utf-8")
    broken_summary = subprocess.run(
        ["python3", reporter, str(broken_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert broken_summary.returncode == 1
    broken_summary_payload = json.loads(broken_summary.stdout)
    assert broken_summary_payload["ok"] is False
    assert broken_summary_payload["counts"]["boundary_break_count"] == 1
    assert "signoff_boundary.training_execution_authorized" in broken_summary_payload["signoffs"][0][
        "boundary_breaks"
    ]


