def test_phase61_local_feature_completion_validated_closure_handoff_signoff_summary_validator_accepts_pending_and_completed_summaries(
    tmp_path,
):
    generator = (
        "scripts/create_documentops_local_feature_completion_validated_closure_handoff_pending_signoff.py"
    )
    reporter = "scripts/summarize_documentops_local_feature_completion_validated_closure_handoff_signoffs.py"
    validator = (
        "scripts/validate_documentops_local_feature_completion_validated_closure_handoff_signoff_summary.py"
    )
    pending_path = tmp_path / "phase61_pending_signoff.json"
    pending_summary_path = tmp_path / "phase61_pending_summary.json"

    generated = subprocess.run(
        [
            "python3",
            generator,
            "--output",
            str(pending_path),
            "--signoff-id",
            "documentops_local_feature_completion_validated_closure_handoff_signoff_phase61pending",
            "--created-at",
            "2026-05-27T00:00:00+09:00",
        ],
        capture_output=True,
        check=False,
        text=True,
    )

    assert generated.returncode == 0

    pending_summary = subprocess.run(
        [
            "python3",
            reporter,
            str(pending_path),
            "--generated-at",
            "2026-05-27T00:00:00+09:00",
            "--output",
            str(pending_summary_path),
        ],
        capture_output=True,
        check=False,
        text=True,
    )

    assert pending_summary.returncode == 0
    pending_valid = subprocess.run(
        ["python3", validator, str(pending_summary_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert pending_valid.returncode == 0
    assert "PASS documentops local feature completion validated closure handoff signoff summary validated" in (
        pending_valid.stdout
    )
    assert "signoff_summary_valid=true" in pending_valid.stdout
    assert "completion_ready=false" in pending_valid.stdout
    assert "readiness_status=pending_validated_closure_handoff_signoff_review_no_training_authorization" in (
        pending_valid.stdout
    )
