    assert pending_summary_payload["report_type"] == (
        "document_ops_phase69_local_feature_completion_validated_closure_handoff_signoff_closure_receipt_validated_handoff_signoff_summary"
    )
    assert pending_summary_payload["ok"] is True
    assert pending_summary_payload["completion_ready"] is False
    assert pending_summary_payload["readiness"]["status"] == (
        "pending_validated_closure_receipt_summary_handoff_signoff_review_no_training_authorization"
    )
