def test_phase76_local_feature_completion_validated_closure_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_validator_accepts_completed_copy_and_rejects_boundary_breaks(
    tmp_path,
):
    validator = (
        "scripts/validate_documentops_local_feature_completion_validated_closure_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff.py"
    )
    template_path = (
        "docs/specs/hermes_decisiondoc_agent/"
        "phase76_local_feature_completion_validated_closure_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff/"
        "validated_closure_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_template.json"
    )

    pending_result = subprocess.run(
        ["python3", validator, template_path],
        capture_output=True,
        check=False,
        text=True,
    )
    assert pending_result.returncode == 0
    assert (
        "PASS documentops local feature completion validated closure handoff signoff closure receipt validated handoff signoff closure receipt validated handoff sign-off validated"
        in pending_result.stdout
    )
    assert "completed=false" in pending_result.stdout
    assert "decision=pending" in pending_result.stdout

    completed = json.load(open(template_path, encoding="utf-8"))
    completed["signoff_id"] = (
        "documentops_local_feature_completion_validated_closure_receipt_validated_handoff_summary_handoff_signoff_phase76done"
    )
    completed["created_at"] = "2026-05-28T00:00:00+09:00"
    completed["decision"] = "accepted"
    completed["reviewer"] = {
        "name": "Phase 76 Reviewer",
        "title_or_team": "Release Review",
        "reviewed_at": "2026-05-28T00:00:00+09:00",
    }
    completed["evidence_reviewed"] = [
        "docs/specs/hermes_decisiondoc_agent/phase75_local_feature_completion_validated_closure_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff/validated_closure_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff.json",
        "docs/specs/hermes_decisiondoc_agent/phase76_local_feature_completion_validated_closure_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff/validated_closure_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_template.json",
    ]
    completed["findings"]["summary"] = (
        "Phase 75 validated closure receipt validated handoff summary handoff is accepted as evidence-only local closure."
    )
    for key in completed["acknowledgements"]:
        completed["acknowledgements"][key] = True
    completed_path = tmp_path / "phase76_completed_signoff.json"
    completed_path.write_text(json.dumps(completed, ensure_ascii=False, indent=2), encoding="utf-8")
    completed_result = subprocess.run(
        ["python3", validator, str(completed_path), "--require-complete"],
        capture_output=True,
        check=False,
        text=True,
    )

    assert completed_result.returncode == 0
    assert "completed=true" in completed_result.stdout
    assert "decision=accepted" in completed_result.stdout
    assert "source_handoff_validation_ok=true" in completed_result.stdout
    assert "aws_cost_boundary=no_cost_increase" in completed_result.stdout
    assert "training_boundary=not_authorized" in completed_result.stdout

    broken = json.loads(json.dumps(completed))
    broken["signoff_boundary"]["training_execution_authorized"] = True
    broken_path = tmp_path / "phase76_broken_training_signoff.json"
    broken_path.write_text(json.dumps(broken, ensure_ascii=False, indent=2), encoding="utf-8")
    broken_result = subprocess.run(
        ["python3", validator, str(broken_path), "--require-complete"],
        capture_output=True,
        check=False,
        text=True,
    )

    assert broken_result.returncode == 1
    assert (
        "FAIL documentops local feature completion validated closure handoff signoff closure receipt validated handoff signoff closure receipt validated handoff sign-off validation failed"
        in broken_result.stdout
    )
    assert "signoff_boundary.training_execution_authorized must be false" in broken_result.stdout

    incomplete = json.loads(json.dumps(completed))
    incomplete["acknowledgements"]["no_training_execution_acknowledged"] = False
    incomplete_path = tmp_path / "phase76_incomplete_signoff.json"
    incomplete_path.write_text(json.dumps(incomplete, ensure_ascii=False, indent=2), encoding="utf-8")
    incomplete_result = subprocess.run(
        ["python3", validator, str(incomplete_path), "--require-complete"],
        capture_output=True,
        check=False,
        text=True,
    )

    assert incomplete_result.returncode == 1
    assert "completed signoff requires acknowledgements.no_training_execution_acknowledged=true" in (
        incomplete_result.stdout
    )


