def test_phase81_local_feature_completion_validated_closure_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validator_accepts_receipt_and_rejects_boundary_break(
    tmp_path,
):
    validator = (
        "scripts/validate_documentops_local_feature_completion_validated_closure_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt.py"
    )
    receipt_path = (
        "docs/specs/hermes_decisiondoc_agent/"
        "phase81_local_feature_completion_validated_closure_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt/"
        "validated_closure_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt.json"
    )

    result = subprocess.run(
        ["python3", validator],
        capture_output=True,
        check=False,
        text=True,
    )

    assert result.returncode == 0
    assert (
        "PASS documentops local feature completion validated closure handoff signoff closure receipt validated handoff signoff closure receipt validated handoff signoff closure receipt validated"
        in result.stdout
    )
    assert "closure_receipt_valid=true" in result.stdout
    assert "source_closure_gate_valid=true" in result.stdout
    assert "service_operation_state=freeze_preserved" in result.stdout
    assert "operator_decision=keep_service_frozen" in result.stdout
    assert "aws_cost_boundary=no_cost_increase" in result.stdout
    assert "training_boundary=not_authorized" in result.stdout

    broken = json.load(open(receipt_path, encoding="utf-8"))
    broken["receipt_boundary"]["service_resume_authorized"] = True
    broken_path = tmp_path / "phase81_broken_service_resume_receipt.json"
    broken_path.write_text(json.dumps(broken, ensure_ascii=False, indent=2), encoding="utf-8")
    broken_result = subprocess.run(
        ["python3", validator, str(broken_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert broken_result.returncode == 1
    assert (
        "FAIL documentops local feature completion validated closure handoff signoff closure receipt validated handoff signoff closure receipt validated handoff signoff closure receipt validation failed"
        in broken_result.stdout
    )
    assert "receipt_boundary.service_resume_authorized must be false" in broken_result.stdout

    broken_hash = json.load(open(receipt_path, encoding="utf-8"))
    broken_hash["source_hashes"]["phase80_closure_index_sha256"] = "0" * 64
    broken_hash_path = tmp_path / "phase81_broken_hash_receipt.json"
    broken_hash_path.write_text(json.dumps(broken_hash, ensure_ascii=False, indent=2), encoding="utf-8")
    broken_hash_result = subprocess.run(
        ["python3", validator, str(broken_hash_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert broken_hash_result.returncode == 1
    assert "source_hashes.phase80_closure_index_sha256 must match" in broken_hash_result.stdout


