    broken_boundary = json.load(open(completed_summary_path, encoding="utf-8"))
    broken_boundary["readiness"]["training_execution_authorized"] = True
    broken_boundary_path = tmp_path / "phase88_broken_training_summary.json"
    broken_boundary_path.write_text(json.dumps(broken_boundary, ensure_ascii=False, indent=2), encoding="utf-8")
    broken_boundary_result = subprocess.run(
        ["python3", validator, str(broken_boundary_path), "--require-complete"],
        capture_output=True,
        check=False,
        text=True,
    )

    assert broken_boundary_result.returncode == 1
    assert "readiness.training_execution_authorized must be false" in broken_boundary_result.stdout

