def test_phase97_local_feature_completion_validated_closure_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_summary_validator_accepts_pending_and_completed_summaries(
    tmp_path,
):
    generator = "scripts/create_documentops_phase94_validated_closure_receipt_summary_handoff_pending_signoff.py"
    reporter = "scripts/summarize_documentops_phase94_validated_closure_receipt_summary_handoff_signoffs.py"
    validator = "scripts/validate_documentops_phase96_validated_closure_receipt_summary_handoff_signoff_summary.py"
    pending_path = tmp_path / "phase97_pending_signoff.json"
    pending_summary_path = tmp_path / "phase97_pending_signoff_summary.json"
    pending_markdown_path = tmp_path / "phase97_pending_signoff_summary.md"

    generated = subprocess.run(
        [
            "python3",
            generator,
            "--output",
            str(pending_path),
            "--signoff-id",
            "documentops_local_feature_completion_phase93_validated_closure_receipt_summary_handoff_signoff_phase97pending",
            "--created-at",
            "2026-06-02T00:00:00+09:00",
        ],
        capture_output=True,
        check=False,
        text=True,
    )

    assert generated.returncode == 0
    assert pending_path.exists()

    pending_summary = subprocess.run(
        [
            "python3",
            reporter,
            str(pending_path),
            "--generated-at",
            "2026-06-02T00:00:00+09:00",
            "--output",
            str(pending_summary_path),
            "--markdown-output",
            str(pending_markdown_path),
        ],
        capture_output=True,
        check=False,
        text=True,
    )

    assert pending_summary.returncode == 0
    pending_summary_payload = json.loads(pending_summary.stdout)
    assert pending_summary_payload["completion_ready"] is False
    assert pending_summary_payload["readiness"]["status"] == (
        "pending_phase93_validated_closure_receipt_summary_handoff_signoff_review_no_training_authorization"
    )
    assert pending_summary_path.exists()
    assert pending_markdown_path.exists()

    pending_validation = subprocess.run(
        ["python3", validator, str(pending_summary_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert pending_validation.returncode == 0
    assert (
        "PASS documentops local feature completion validated closure handoff signoff closure receipt validated handoff signoff closure receipt validated handoff signoff closure receipt validated handoff signoff closure receipt validated handoff signoff summary validated"
        in pending_validation.stdout
    )
    assert "signoff_summary_valid=true" in pending_validation.stdout
    assert "completion_ready=false" in pending_validation.stdout
    assert (
        "readiness_status=pending_phase93_validated_closure_receipt_summary_handoff_signoff_review_no_training_authorization"
        in pending_validation.stdout
    )
    assert "signoff_count=1" in pending_validation.stdout

    pending_require_complete_validation = subprocess.run(
        ["python3", validator, str(pending_summary_path), "--require-complete"],
        capture_output=True,
        check=False,
        text=True,
    )

    assert pending_require_complete_validation.returncode == 1
    assert "completion_ready must be true when --require-complete is used" in pending_require_complete_validation.stdout
    assert "all signoffs must be completed when --require-complete is used" in pending_require_complete_validation.stdout

    completed_payload = json.load(open(pending_path, encoding="utf-8"))
    completed_payload["signoff_id"] = (
        "documentops_local_feature_completion_phase93_validated_closure_receipt_summary_handoff_signoff_phase97done"
    )
    completed_payload["decision"] = "accepted"
    completed_payload["reviewer"] = {
        "name": "Phase 97 Reviewer",
        "title_or_team": "Release Review",
        "reviewed_at": "2026-06-02T00:00:00+09:00",
    }
    completed_payload["evidence_reviewed"] = [
        "docs/specs/hermes_decisiondoc_agent/phase93_local_feature_completion_validated_closure_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff/validated_closure_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff.json",
        "docs/specs/hermes_decisiondoc_agent/phase94_local_feature_completion_validated_closure_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff/validated_closure_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_template.json",
    ]
    completed_payload["findings"]["summary"] = (
        "Phase 94 validated closure receipt summary handoff sign-off evidence accepted without operation authorization."
    )
    for key in completed_payload["acknowledgements"]:
        completed_payload["acknowledgements"][key] = True
    completed_path = tmp_path / "phase97_completed_signoff.json"
    completed_path.write_text(json.dumps(completed_payload, ensure_ascii=False, indent=2), encoding="utf-8")
    completed_summary = subprocess.run(
        [
            "python3",
            reporter,
            str(completed_path),
            "--generated-at",
            "2026-06-02T00:00:00+09:00",
            "--require-complete",
        ],
        capture_output=True,
        check=False,
        text=True,
    )

    assert completed_summary.returncode == 0
    completed_summary_payload = json.loads(completed_summary.stdout)
    assert completed_summary_payload["completion_ready"] is True
    assert completed_summary_payload["readiness"]["status"] == (
        "all_phase93_validated_closure_receipt_summary_handoff_signoffs_accepted_no_cost_boundary_preserved"
    )

    completed_summary_path = tmp_path / "phase97_completed_signoff_summary.json"
    completed_summary_path.write_text(
        json.dumps(completed_summary_payload, ensure_ascii=False, indent=2),
        encoding="utf-8",
    )
    completed_validation = subprocess.run(
        ["python3", validator, str(completed_summary_path), "--require-complete"],
        capture_output=True,
        check=False,
        text=True,
    )

    assert completed_validation.returncode == 0
    assert "completion_ready=true" in completed_validation.stdout
    assert (
        "readiness_status=all_phase93_validated_closure_receipt_summary_handoff_signoffs_accepted_no_cost_boundary_preserved"
        in completed_validation.stdout
    )

    broken_boundary_payload = json.loads(json.dumps(pending_summary_payload))
    broken_boundary_payload["readiness"]["training_execution_authorized"] = True
    broken_boundary_path = tmp_path / "phase97_broken_boundary_summary.json"
    broken_boundary_path.write_text(json.dumps(broken_boundary_payload, ensure_ascii=False, indent=2), encoding="utf-8")
    broken_boundary_validation = subprocess.run(
        ["python3", validator, str(broken_boundary_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert broken_boundary_validation.returncode == 1
    assert "readiness.training_execution_authorized must be false" in broken_boundary_validation.stdout

    broken_hash_payload = json.loads(json.dumps(completed_summary_payload))
    broken_hash_payload["signoffs"][0]["sha256"] = "0" * 64
    broken_hash_path = tmp_path / "phase97_broken_hash_summary.json"
    broken_hash_path.write_text(json.dumps(broken_hash_payload, ensure_ascii=False, indent=2), encoding="utf-8")
    broken_hash_validation = subprocess.run(
        ["python3", validator, str(broken_hash_path), "--require-complete"],
        capture_output=True,
        check=False,
        text=True,
    )

    assert broken_hash_validation.returncode == 1
    assert "signoffs[1].sha256 must match linked sign-off file" in broken_hash_validation.stdout


