def test_phase99_local_feature_completion_validated_closure_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validator_accepts_receipt_and_rejects_boundary_break(
    tmp_path,
):
    validator = (
        "scripts/validate_documentops_phase98_validated_closure_receipt_summary_handoff_signoff_closure_receipt.py"
    )
    receipt_path = (
        "docs/specs/hermes_decisiondoc_agent/"
        "phase99_local_feature_completion_validated_closure_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt/"
        "validated_closure_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt_validated_handoff_signoff_closure_receipt.json"
    )

    result = subprocess.run(
        ["python3", validator],
        capture_output=True,
        check=False,
        text=True,
    )

    assert result.returncode == 0
    assert (
        "PASS documentops local feature completion validated closure handoff signoff closure receipt validated handoff signoff closure receipt validated handoff signoff closure receipt validated handoff signoff closure receipt validated handoff signoff closure receipt validated"
        in result.stdout
    )
    assert "closure_receipt_valid=true" in result.stdout
    assert "source_closure_gate_valid=true" in result.stdout
