    assert broken_result.returncode == 1
    assert "FAIL documentops phase102 validated closure receipt summary handoff validation failed" in broken_result.stdout
    assert "handoff_boundary.service_resume_authorized must be false" in broken_result.stdout

    broken_training = json.load(open(handoff_path, encoding="utf-8"))
    broken_training["training_execution_authorized"] = True
    broken_training_path = tmp_path / "phase102_broken_training_authorized_handoff.json"
