def test_phase107_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_closure_index_records_full_local_chain():
    report = open(
        "docs/specs/hermes_decisiondoc_agent/"
        "phase107_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_closure_index/"
        "VALIDATED_CLOSURE_RECEIPT_SUMMARY_HANDOFF_SIGNOFF_CLOSURE_INDEX.md",
        encoding="utf-8",
    ).read()
    index_path = (
        "docs/specs/hermes_decisiondoc_agent/"
        "phase107_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_closure_index/"
        "validated_closure_receipt_summary_handoff_signoff_closure_index.json"
    )
    index = json.load(open(index_path, encoding="utf-8"))

    assert "Phase 107 Local Feature Completion Validated Closure Receipt Summary Handoff Sign-Off Closure Index" in report
    assert (
        "VALIDATED_CLOSURE_RECEIPT_SUMMARY_HANDOFF_SIGNOFF_CLOSURE_INDEX_READY_NO_AWS_NO_TRAINING_AUTHORIZATION"
        in report
    )
    assert "Phase 102-106" in report
    assert index["report_type"] == (
        "document_ops_phase107_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_closure_index"
    )
    assert index["phase"] == 107
    assert index["status"] == (
        "validated_closure_receipt_summary_handoff_signoff_closure_index_ready_no_aws_no_training_authorization"
    )
    assert index["closure_scope"] == (
        "local_read_only_phase102_to_phase106_validated_closure_receipt_summary_handoff_signoff_closure_validation"
    )
    assert index["recommended_decision"] == "keep_service_frozen"

    expected_artifacts = {
        "phase102_validated_closure_receipt_summary_handoff": 102,
        "phase103_validated_closure_receipt_summary_handoff_signoff_template": 103,
        "phase104_pending_validated_closure_receipt_summary_handoff_signoff_generation_contract": 104,
        "phase105_validated_closure_receipt_summary_handoff_signoff_summary_contract": 105,
        "phase106_validated_closure_receipt_summary_handoff_signoff_summary_validation_contract": 106,
    }
    artifacts = {artifact["id"]: artifact for artifact in index["source_artifacts"]}
    assert set(artifacts) == set(expected_artifacts)
    for artifact_id, expected_phase in expected_artifacts.items():
        artifact = artifacts[artifact_id]
        assert artifact["phase"] == expected_phase
        with open(artifact["path"], "rb") as artifact_file:
            assert artifact["sha256"] == hashlib.sha256(artifact_file.read()).hexdigest()
        assert os.path.exists(artifact["validator"])

    validator = index["closure_validator"]
    assert validator["path"] == (
        "scripts/validate_documentops_phase102_to_phase106_validated_closure_receipt_summary_handoff_signoff_closure_index.py"
    )
    with open(validator["path"], "rb") as validator_file:
        assert validator["sha256"] == hashlib.sha256(validator_file.read()).hexdigest()
    assert validator["checks_source_artifact_hashes"] is True
    assert validator["runs_phase102_validator"] is True
    assert validator["validates_phase103_template"] is True
    assert validator["generates_temporary_phase104_pending_signoff"] is True
    assert validator["builds_temporary_phase105_summary"] is True
    assert validator["runs_phase106_summary_validator"] is True
    assert validator["writes_repo_files"] is False
    assert index["closure_policy"]["pending_summary_can_validate_as_non_approval_evidence"] is True
