def test_phase119_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_closure_receipt_summary_validator_accepts_summary_and_rejects_boundary_breaks(
    tmp_path,
):
    reporter = "scripts/summarize_documentops_phase117_validated_closure_receipts.py"
    validator = (
        "scripts/validate_documentops_phase118_validated_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_closure_receipt_summary.py"
    )
    receipt_path = (
        "docs/specs/hermes_decisiondoc_agent/"
        "phase117_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_closure_receipt/"
        "validated_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_closure_receipt.json"
    )
    summary_path = tmp_path / "phase119_validated_closure_receipt_summary.json"

    summary_result = subprocess.run(
        [
            "python3",
            reporter,
            receipt_path,
            "--generated-at",
            "2026-06-02T00:00:00+09:00",
            "--output",
            str(summary_path),
        ],
        capture_output=True,
        check=False,
        text=True,
    )

    assert summary_result.returncode == 0
    valid_result = subprocess.run(
        ["python3", validator, str(summary_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert valid_result.returncode == 0
    assert "PASS documentops phase118 validated closure receipt summary validated" in valid_result.stdout
    assert "phase117_validated_closure_receipt_summary_valid=true" in valid_result.stdout
    assert "receipt_count=1" in valid_result.stdout
    assert "readiness_status=all_phase117_validated_closure_receipts_confirm_no_cost_freeze" in valid_result.stdout
    assert "service_operation_state=freeze_preserved" in valid_result.stdout
    assert "aws_cost_boundary=no_cost_increase" in valid_result.stdout
    assert "training_boundary=not_authorized" in valid_result.stdout

    broken = json.load(open(summary_path, encoding="utf-8"))
    broken["readiness"]["training_execution_started"] = True
    broken_path = tmp_path / "phase119_broken_training_summary.json"
    broken_path.write_text(json.dumps(broken, ensure_ascii=False, indent=2), encoding="utf-8")
    broken_result = subprocess.run(
        ["python3", validator, str(broken_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert broken_result.returncode == 1
    assert "FAIL documentops phase118 validated closure receipt summary validation failed" in broken_result.stdout
    assert "readiness.training_execution_started must be false" in broken_result.stdout

    broken_hash = json.load(open(summary_path, encoding="utf-8"))
