def test_phase141_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_summary_reports_pending_completed_and_boundary_breaks(
    tmp_path,
):
    generator = "scripts/create_documentops_phase139_validated_closure_receipt_summary_handoff_signoff_pending_signoff.py"
    reporter = "scripts/summarize_documentops_phase139_validated_closure_receipt_summary_handoff_signoffs.py"
    pending_path = tmp_path / "phase141_pending_signoff.json"
    summary_path = tmp_path / "phase141_signoff_summary.json"
    markdown_path = tmp_path / "phase141_signoff_summary.md"

    generated = subprocess.run(
        [
            "python3",
            generator,
            "--output",
            str(pending_path),
            "--signoff-id",
            "documentops_local_feature_completion_phase138_validated_closure_receipt_summary_handoff_signoff_phase141pending",
            "--created-at",
            "2026-06-04T00:00:00+09:00",
        ],
        capture_output=True,
        check=False,
        text=True,
    )

    assert generated.returncode == 0
    assert pending_path.exists()

    pending_summary = subprocess.run(
        [
            "python3",
            reporter,
            str(pending_path),
            "--generated-at",
            "2026-06-04T00:00:00+09:00",
            "--output",
            str(summary_path),
            "--markdown-output",
            str(markdown_path),
        ],
        capture_output=True,
        check=False,
        text=True,
    )

    assert pending_summary.returncode == 0
    pending_summary_payload = json.loads(pending_summary.stdout)
    assert pending_summary_payload["report_type"] == (
        "document_ops_phase141_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_summary"
    )
    assert pending_summary_payload["ok"] is True
    assert pending_summary_payload["completion_ready"] is False
    assert pending_summary_payload["readiness"]["status"] == (
        "pending_phase138_validated_closure_receipt_summary_handoff_signoff_review_no_training_authorization"
    )
    assert pending_summary_payload["counts"]["signoff_count"] == 1
    assert pending_summary_payload["counts"]["valid_signoff_count"] == 1
    assert pending_summary_payload["counts"]["pending_signoff_count"] == 1
    assert pending_summary_payload["counts"]["completed_signoff_count"] == 0
    assert pending_summary_payload["counts"]["boundary_break_count"] == 0
    assert pending_summary_payload["side_effect_boundary"]["service_resume_authorized"] is False
    assert pending_summary_payload["side_effect_boundary"]["training_execution_started"] is False
    assert summary_path.exists()
    assert markdown_path.exists()
    assert (
        "pending_phase138_validated_closure_receipt_summary_handoff_signoff_review_no_training_authorization"
        in markdown_path.read_text(encoding="utf-8")
    )

    pending_require_complete = subprocess.run(
        ["python3", reporter, str(pending_path), "--require-complete"],
        capture_output=True,
        check=False,
        text=True,
    )

    assert pending_require_complete.returncode == 1
    pending_require_complete_payload = json.loads(pending_require_complete.stdout)
    assert "completed_accepted_signoffs_required" in pending_require_complete_payload["readiness"][
        "blocker_reasons"
    ]

    completed_payload = json.load(open(pending_path, encoding="utf-8"))
    completed_payload["signoff_id"] = (
        "documentops_local_feature_completion_phase138_validated_closure_receipt_summary_handoff_signoff_phase141done"
    )
    completed_payload["decision"] = "accepted"
    completed_payload["reviewer"] = {
        "name": "Phase 141 Reviewer",
        "title_or_team": "Release Review",
        "reviewed_at": "2026-06-04T00:00:00+09:00",
    }
    completed_payload["evidence_reviewed"] = [
        "docs/specs/hermes_decisiondoc_agent/phase138_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff/validated_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff.json",
        "docs/specs/hermes_decisiondoc_agent/phase139_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff/validated_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_template.json",
    ]
    completed_payload["findings"]["summary"] = (
        "Phase 139 validated closure receipt summary handoff sign-off evidence accepted without operation authorization."
    )
    for key in completed_payload["acknowledgements"]:
        completed_payload["acknowledgements"][key] = True
    completed_path = tmp_path / "phase141_completed_signoff.json"
    completed_path.write_text(json.dumps(completed_payload, ensure_ascii=False, indent=2), encoding="utf-8")
    completed_summary = subprocess.run(
        [
            "python3",
            reporter,
            str(completed_path),
            "--generated-at",
            "2026-06-04T00:00:00+09:00",
            "--require-complete",
        ],
        capture_output=True,
        check=False,
        text=True,
    )

    assert completed_summary.returncode == 0
    completed_summary_payload = json.loads(completed_summary.stdout)
    assert completed_summary_payload["ok"] is True
    assert completed_summary_payload["completion_ready"] is True
    assert completed_summary_payload["readiness"]["status"] == (
        "all_phase138_validated_closure_receipt_summary_handoff_signoffs_accepted_no_cost_boundary_preserved"
    )
    assert completed_summary_payload["counts"]["completed_signoff_count"] == 1
    assert completed_summary_payload["counts"]["accepted_signoff_count"] == 1
