def test_phase142_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_summary_validator_accepts_pending_and_completed_summaries(
    tmp_path,
):
    generator = "scripts/create_documentops_phase139_validated_closure_receipt_summary_handoff_signoff_pending_signoff.py"
    reporter = "scripts/summarize_documentops_phase139_validated_closure_receipt_summary_handoff_signoffs.py"
