    pending_summary_path = tmp_path / "phase142_pending_signoff_summary.json"
    pending_markdown_path = tmp_path / "phase142_pending_signoff_summary.md"

    generated = subprocess.run(
        [
            "python3",
            generator,
            "--output",
            str(pending_path),
            "--signoff-id",
            "documentops_local_feature_completion_phase138_validated_closure_receipt_summary_handoff_signoff_phase142pending",
            "--created-at",
            "2026-06-04T00:00:00+09:00",
        ],
        capture_output=True,
        check=False,
        text=True,
    )

    assert generated.returncode == 0
    assert pending_path.exists()

    pending_summary = subprocess.run(
        [
            "python3",
            reporter,
            str(pending_path),
            "--generated-at",
            "2026-06-04T00:00:00+09:00",
            "--output",
            str(pending_summary_path),
            "--markdown-output",
            str(pending_markdown_path),
        ],
        capture_output=True,
        check=False,
        text=True,
    )

    assert pending_summary.returncode == 0
