    assert "completed_accepted_signoffs_required" in pending_require_complete_payload["readiness"][
        "blocker_reasons"
    ]

    completed_payload = json.load(open(pending_path, encoding="utf-8"))
    completed_payload["signoff_id"] = (
        "documentops_local_feature_completion_phase147_validated_closure_receipt_summary_handoff_signoff_phase150done"
    )
    completed_payload["decision"] = "accepted"
    completed_payload["reviewer"] = {
        "name": "Phase 150 Reviewer",
        "title_or_team": "Release Review",
        "reviewed_at": "2026-06-04T00:00:00+09:00",
    }
    completed_payload["evidence_reviewed"] = [
        "docs/specs/hermes_decisiondoc_agent/phase147_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff/validated_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff.json",
        "docs/specs/hermes_decisiondoc_agent/phase148_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff/validated_closure_receipt_summary_handoff_signoff_closure_receipt_summary_handoff_signoff_template.json",
    ]
    completed_payload["findings"]["summary"] = (
        "Phase 148 validated closure receipt summary handoff sign-off evidence accepted without operation authorization."
    )
    for key in completed_payload["acknowledgements"]:
        completed_payload["acknowledgements"][key] = True
    completed_path = tmp_path / "phase150_completed_signoff.json"
    completed_path.write_text(json.dumps(completed_payload, ensure_ascii=False, indent=2), encoding="utf-8")
    completed_summary = subprocess.run(
        [
            "python3",
            reporter,
            str(completed_path),
            "--generated-at",
            "2026-06-04T00:00:00+09:00",
            "--require-complete",
        ],
        capture_output=True,
        check=False,
        text=True,
    )

    assert completed_summary.returncode == 0
