    broken_hash_result = subprocess.run(
        ["python3", validator, str(broken_hash_path)],
        capture_output=True,
        check=False,
        text=True,
    )
    assert broken_hash_result.returncode == 1
    assert "signoffs[1].sha256 must match linked Phase 148 sign-off file" in broken_hash_result.stdout


