def test_phase152_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_closure_index_validator_accepts_chain_and_rejects_boundary_break(
    tmp_path,
):
    validator = (
        "scripts/validate_documentops_phase147_to_phase151_validated_closure_receipt_summary_handoff_signoff_closure_index.py"
    )
