    result = subprocess.run(
        ["python3", validator],
        capture_output=True,
        check=False,
        text=True,
    )

    assert result.returncode == 0
    assert "PASS documentops phase152 validated closure receipt summary handoff sign-off closure index validated" in (
        result.stdout
    )
    assert "closure_index_valid=true" in result.stdout
    assert "source_artifact_count=5" in result.stdout
