def test_phase188_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_closure_index_validator_accepts_chain_and_rejects_boundary_break(
    tmp_path,
):
    validator = (
        "scripts/validate_documentops_phase183_to_phase187_validated_closure_receipt_summary_handoff_signoff_closure_index.py"
    )
    index_path = (
        "docs/specs/hermes_decisiondoc_agent/"
        "phase188_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_closure_index/"
        "validated_closure_receipt_summary_handoff_signoff_closure_index.json"
    )

    result = subprocess.run(
        ["python3", validator],
        capture_output=True,
        check=False,
        text=True,
    )

    assert result.returncode == 0
    assert "PASS documentops phase188 validated closure receipt summary handoff sign-off closure index validated" in (
        result.stdout
    )
    assert "closure_index_valid=true" in result.stdout
    assert "source_artifact_count=5" in result.stdout
    assert "probe_count=5" in result.stdout
    assert (
        "temporary_summary_readiness=pending_phase183_validated_closure_receipt_summary_handoff_signoff_review_no_training_authorization"
        in result.stdout
    )
    assert "temporary_summary_validation_ok=true" in result.stdout
    assert "service_operation_state=freeze_preserved" in result.stdout
    assert "recommended_decision=keep_service_frozen" in result.stdout
    assert "aws_cost_boundary=no_cost_increase" in result.stdout
    assert "training_boundary=not_authorized" in result.stdout

    broken = json.load(open(index_path, encoding="utf-8"))
    broken["closure_boundary"]["training_execution_started"] = True
    broken_path = tmp_path / "phase188_broken_training_index.json"
    broken_path.write_text(json.dumps(broken, ensure_ascii=False, indent=2), encoding="utf-8")
    broken_result = subprocess.run(
        ["python3", validator, str(broken_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert broken_result.returncode == 1
    assert "FAIL documentops phase188 validated closure receipt summary handoff sign-off closure index validation failed" in (
        broken_result.stdout
    )
    assert "closure_boundary.training_execution_started must be false" in broken_result.stdout

    broken_hash = json.load(open(index_path, encoding="utf-8"))
    broken_hash["source_artifacts"][0]["sha256"] = "0" * 64
    broken_hash_path = tmp_path / "phase188_broken_hash_index.json"
    broken_hash_path.write_text(json.dumps(broken_hash, ensure_ascii=False, indent=2), encoding="utf-8")
    broken_hash_result = subprocess.run(
        ["python3", validator, str(broken_hash_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert broken_hash_result.returncode == 1
    assert "source_artifacts.phase183_validated_closure_receipt_summary_handoff.sha256 must match" in (
        broken_hash_result.stdout
    )


