def test_phase218_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_closure_receipt_summary_validator_accepts_summary_and_rejects_boundary_breaks(
    tmp_path,
):
    reporter = "scripts/summarize_documentops_phase216_validated_closure_receipts.py"
    validator = "scripts/validate_documentops_phase217_validated_closure_receipt_summary.py"
    receipt_path = (
        "docs/specs/hermes_decisiondoc_agent/"
        "phase216_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_closure_receipt/"
        "validated_closure_receipt_summary_handoff_signoff_closure_receipt.json"
    )
    summary_path = tmp_path / "phase218_summary.json"

    summarized = subprocess.run(
        [
            "python3",
            reporter,
            receipt_path,
            "--generated-at",
            "2026-06-08T00:00:00+09:00",
            "--output",
            str(summary_path),
        ],
        capture_output=True,
        check=False,
        text=True,
    )
    assert summarized.returncode == 0

    valid_result = subprocess.run(
        ["python3", validator, str(summary_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert valid_result.returncode == 0
    assert "PASS documentops phase217 validated closure receipt summary validated" in valid_result.stdout
    assert "phase217_validated_closure_receipt_summary_valid=true" in valid_result.stdout
    assert "receipt_count=1" in valid_result.stdout
    assert "readiness_status=all_phase216_validated_closure_receipts_confirm_no_cost_freeze" in valid_result.stdout
    assert "service_operation_state=freeze_preserved" in valid_result.stdout
    assert "aws_cost_boundary=no_cost_increase" in valid_result.stdout
    assert "training_boundary=not_authorized" in valid_result.stdout

    json_result = subprocess.run(
        ["python3", validator, str(summary_path), "--json"],
        capture_output=True,
        check=False,
        text=True,
    )
    validation = json.loads(json_result.stdout)
    assert json_result.returncode == 0
    assert validation["ok"] is True
    assert validation["phase217_validated_closure_receipt_summary_valid"] is True

    broken = json.load(open(summary_path, encoding="utf-8"))
