def test_phase220_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_validator_accepts_completed_copy_and_rejects_boundary_breaks(
    tmp_path,
):
    validator = "scripts/validate_documentops_phase219_validated_closure_receipt_summary_handoff_signoff.py"
    template_path = (
        "docs/specs/hermes_decisiondoc_agent/"
        "phase220_local_feature_completion_validated_closure_receipt_summary_handoff_signoff/"
        "validated_closure_receipt_summary_handoff_signoff_template.json"
    )

    pending_result = subprocess.run(
        ["python3", validator, template_path],
        capture_output=True,
        check=False,
        text=True,
    )

    assert pending_result.returncode == 0
    assert "PASS documentops phase220 validated closure receipt summary handoff sign-off validated" in (
        pending_result.stdout
    )
    assert "completed=false" in pending_result.stdout
    assert "decision=pending" in pending_result.stdout
    assert "source_handoff_validation_ok=true" in pending_result.stdout
    assert "service_operation_state=freeze_preserved" in pending_result.stdout
    assert "aws_cost_boundary=no_cost_increase" in pending_result.stdout
    assert "training_boundary=not_authorized" in pending_result.stdout

    completed = json.load(open(template_path, encoding="utf-8"))
    completed["signoff_id"] = (
        "documentops_local_feature_completion_phase219_validated_closure_receipt_summary_handoff_signoff_phase220done"
    )
    completed["created_at"] = "2026-06-08T00:00:00+09:00"
    completed["decision"] = "accepted"
    completed["reviewer"] = {
        "name": "Local Reviewer",
        "reviewed_at": "2026-06-08T00:00:00+09:00",
        "title_or_team": "Release Review",
    }
    completed["evidence_reviewed"] = [
        completed["source_handoff"]["path"],
        template_path,
    ]
    completed["findings"]["summary"] = "Phase 219 handoff evidence accepted for local no-cost review."
    for key in completed["acknowledgements"]:
        completed["acknowledgements"][key] = True
    completed_path = tmp_path / "phase220_completed_signoff.json"
    completed_path.write_text(json.dumps(completed, ensure_ascii=False, indent=2), encoding="utf-8")

    completed_result = subprocess.run(
        ["python3", validator, str(completed_path), "--require-complete"],
        capture_output=True,
        check=False,
        text=True,
    )

    assert completed_result.returncode == 0
    assert "completed=true" in completed_result.stdout
    assert "decision=accepted" in completed_result.stdout
    assert "source_handoff_validation_ok=true" in completed_result.stdout
    assert "service_operation_state=freeze_preserved" in completed_result.stdout
    assert "aws_cost_boundary=no_cost_increase" in completed_result.stdout
    assert "training_boundary=not_authorized" in completed_result.stdout

    broken = json.load(open(template_path, encoding="utf-8"))
    broken["signoff_boundary"]["training_execution_authorized"] = True
    broken_path = tmp_path / "phase220_broken_training_signoff.json"
    broken_path.write_text(json.dumps(broken, ensure_ascii=False, indent=2), encoding="utf-8")
    broken_result = subprocess.run(
        ["python3", validator, str(broken_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert broken_result.returncode == 1
    assert "FAIL documentops phase220 validated closure receipt summary handoff sign-off validation failed" in (
        broken_result.stdout
    )
    assert "signoff_boundary.training_execution_authorized must be false" in broken_result.stdout

    broken_hash = json.load(open(template_path, encoding="utf-8"))
    broken_hash["source_handoff"]["sha256"] = "0" * 64
    broken_hash_path = tmp_path / "phase220_broken_handoff_hash_signoff.json"
    broken_hash_path.write_text(json.dumps(broken_hash, ensure_ascii=False, indent=2), encoding="utf-8")
    broken_hash_result = subprocess.run(
        ["python3", validator, str(broken_hash_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert broken_hash_result.returncode == 1
    assert "source_handoff.sha256 must match the Phase 219 validated handoff JSON" in (
        broken_hash_result.stdout
    )


