def test_phase223_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_summary_validator_accepts_summary_and_rejects_boundary_breaks(
    tmp_path,
):
    generator = (
        "scripts/create_documentops_phase220_validated_closure_receipt_summary_handoff_signoff_pending_signoff.py"
    )
    reporter = "scripts/summarize_documentops_phase220_validated_closure_receipt_summary_handoff_signoffs.py"
