    summary_path = tmp_path / "phase267_summary.json"
    markdown_path = tmp_path / "phase267_summary.md"
    signoff_id = (
        "documentops_local_feature_completion_phase264_validated_closure_receipt_summary_handoff_signoff_testpending267"
    )

    generated = subprocess.run(
        [
            "python3",
            generator,
            "--output",
            str(pending_path),
            "--signoff-id",
            signoff_id,
            "--created-at",
            "2026-06-11T00:00:00+09:00",
        ],
        capture_output=True,
        check=False,
        text=True,
    )
    assert generated.returncode == 0

    summarized = subprocess.run(
        [
            "python3",
            reporter,
            str(pending_path),
            "--generated-at",
            "2026-06-11T00:00:00+09:00",
            "--output",
            str(summary_path),
            "--markdown-output",
            str(markdown_path),
        ],
        capture_output=True,
        check=False,
        text=True,
    )
    summary = json.loads(summarized.stdout)
    assert summarized.returncode == 0
    assert summary["report_type"] == (
        "document_ops_phase267_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_summary"
    )
    assert summary["schema_version"] == (
        "decisiondoc_documentops_phase265_validated_closure_receipt_summary_handoff_signoff_summary.v1"
    )
    assert summary["ok"] is True
    assert summary["completion_ready"] is False
    assert summary["readiness"]["status"] == (
        "pending_phase264_validated_closure_receipt_summary_handoff_signoff_review_no_training_authorization"
    )
    assert summary["counts"]["signoff_count"] == 1
    assert summary["counts"]["valid_signoff_count"] == 1
    assert summary["counts"]["pending_signoff_count"] == 1
    assert summary["counts"]["completed_signoff_count"] == 0
    assert summary["counts"]["boundary_break_count"] == 0
    assert summary["signoffs"][0]["validation"]["ok"] is True
    assert summary["signoffs"][0]["validation"]["completed"] is False
    assert summary_path.exists()
    assert markdown_path.exists()
    assert "DocumentOps Phase 265 Validated Closure Receipt Summary Handoff Sign-Off Summary" in (
        markdown_path.read_text(encoding="utf-8")
    )
    assert summary["side_effect_boundary"]["reads_local_signoff_records"] is True
    assert summary["side_effect_boundary"]["actual_reviewer_approval_recorded_by_summary"] is False
    assert summary["side_effect_boundary"]["training_execution_started"] is False

    require_complete = subprocess.run(
        ["python3", reporter, str(pending_path), "--require-complete"],
        capture_output=True,
        check=False,
        text=True,
    )
    require_complete_summary = json.loads(require_complete.stdout)
    assert require_complete.returncode == 1
    assert "completed_accepted_signoffs_required" in require_complete_summary["readiness"]["blocker_reasons"]

    broken = json.load(open(pending_path, encoding="utf-8"))
    broken["signoff_boundary"]["training_execution_authorized"] = True
    broken_path = tmp_path / "phase267_broken_training_signoff.json"
    broken_path.write_text(json.dumps(broken, ensure_ascii=False, indent=2), encoding="utf-8")
    broken_result = subprocess.run(
        ["python3", reporter, str(broken_path)],
        capture_output=True,
        check=False,
        text=True,
    )
    broken_summary = json.loads(broken_result.stdout)
    assert broken_result.returncode == 1
    assert "invalid_signoff_records" in broken_summary["readiness"]["blocker_reasons"]
    assert "signoff_boundary_breaks" in broken_summary["readiness"]["blocker_reasons"]
    assert broken_summary["counts"]["boundary_break_count"] == 1
    assert "signoff_boundary.training_execution_authorized" in broken_summary["signoffs"][0]["boundary_breaks"]


