    completed["evidence_reviewed"] = [
        completed["source_handoff"]["path"],
        template_path,
    ]
    completed["findings"]["summary"] = "Phase 291 handoff evidence accepted for local no-cost review."
    for key in completed["acknowledgements"]:
        completed["acknowledgements"][key] = True
    completed_path = tmp_path / "phase292_completed_signoff.json"
