def test_phase309_local_feature_completion_validated_closure_receipt_summary_handoff_validator_accepts_package_and_rejects_boundary_break(
    tmp_path,
):
    validator = "scripts/validate_documentops_phase308_validated_closure_receipt_summary_handoff.py"
    handoff_path = (
        "docs/specs/hermes_decisiondoc_agent/"
        "phase309_local_feature_completion_validated_closure_receipt_summary_handoff/"
        "validated_closure_receipt_summary_handoff.json"
    )

    result = subprocess.run(
        ["python3", validator],
        capture_output=True,
        check=False,
        text=True,
    )

    assert result.returncode == 0
    assert "PASS documentops phase309 validated closure receipt summary handoff validated" in result.stdout
    assert "phase307_validated_closure_receipt_summary_handoff_valid=true" in result.stdout
    assert "handoff_action_count=6" in result.stdout
    assert "generated_summary_validation_ok=true" in result.stdout
    assert "generated_summary_readiness=all_phase306_validated_closure_receipts_confirm_no_cost_freeze" in (
        result.stdout
    )
    assert "service_operation_state=freeze_preserved" in result.stdout
    assert "recommended_decision=keep_service_frozen" in result.stdout
    assert "aws_cost_boundary=no_cost_increase" in result.stdout
    assert "training_boundary=not_authorized" in result.stdout

    broken = json.load(open(handoff_path, encoding="utf-8"))
    broken["handoff_boundary"]["training_execution_started"] = True
    broken_path = tmp_path / "phase309_broken_training_handoff.json"
    broken_path.write_text(json.dumps(broken, ensure_ascii=False, indent=2), encoding="utf-8")
    broken_result = subprocess.run(
        ["python3", validator, str(broken_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert broken_result.returncode == 1
    assert "FAIL documentops phase309 validated closure receipt summary handoff validation failed" in (
        broken_result.stdout
    )
    assert "handoff_boundary.training_execution_started must be false" in broken_result.stdout

    broken_hash = json.load(open(handoff_path, encoding="utf-8"))
    broken_hash["source_summary_validation"]["sha256"] = "0" * 64
    broken_hash_path = tmp_path / "phase309_broken_hash_handoff.json"
    broken_hash_path.write_text(json.dumps(broken_hash, ensure_ascii=False, indent=2), encoding="utf-8")
    broken_hash_result = subprocess.run(
        ["python3", validator, str(broken_hash_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert broken_hash_result.returncode == 1
    assert "source_summary_validation.sha256 must match" in broken_hash_result.stdout


