    markdown_path = tmp_path / "phase312_summary.md"
    signoff_id = (
        "documentops_local_feature_completion_phase309_validated_closure_receipt_summary_handoff_signoff_testpending312"
    )

    generated = subprocess.run(
        [
            "python3",
            generator,
            "--output",
            str(pending_path),
            "--signoff-id",
            signoff_id,
            "--created-at",
            "2026-06-12T00:00:00+09:00",
        ],
        capture_output=True,
        check=False,
        text=True,
    )
    assert generated.returncode == 0

    summarized = subprocess.run(
        [
            "python3",
            reporter,
            str(pending_path),
            "--generated-at",
            "2026-06-12T00:00:00+09:00",
            "--output",
            str(summary_path),
            "--markdown-output",
            str(markdown_path),
        ],
        capture_output=True,
        check=False,
        text=True,
    )
    summary = json.loads(summarized.stdout)
    assert summarized.returncode == 0
    assert summary["report_type"] == (
        "document_ops_phase312_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_summary"
    )
    assert summary["schema_version"] == (
        "decisiondoc_documentops_phase310_validated_closure_receipt_summary_handoff_signoff_summary.v1"
    )
    assert summary["ok"] is True
    assert summary["completion_ready"] is False
    assert summary["readiness"]["status"] == (
        "pending_phase309_validated_closure_receipt_summary_handoff_signoff_review_no_training_authorization"
    )
    assert summary["counts"]["signoff_count"] == 1
    assert summary["counts"]["valid_signoff_count"] == 1
    assert summary["counts"]["pending_signoff_count"] == 1
    assert summary["counts"]["completed_signoff_count"] == 0
    assert summary["counts"]["boundary_break_count"] == 0
    assert summary["signoffs"][0]["validation"]["ok"] is True
    assert summary["signoffs"][0]["validation"]["completed"] is False
    assert summary["signoffs"][0]["source_handoff_path"] == (
        "docs/specs/hermes_decisiondoc_agent/phase309_local_feature_completion_validated_closure_receipt_summary_handoff/validated_closure_receipt_summary_handoff.json"
    )
    assert summary_path.exists()
    assert markdown_path.exists()
