def test_phase323_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_closure_index_validator_accepts_chain_and_rejects_boundary_break(
    tmp_path,
):
    index_path = (
        "docs/specs/hermes_decisiondoc_agent/"
        "phase323_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_closure_index/"
        "validated_closure_receipt_summary_handoff_signoff_closure_index.json"
    )
    validator = (
        "scripts/validate_documentops_phase318_to_phase322_validated_closure_receipt_summary_handoff_signoff_closure_index.py"
    )

    valid_result = subprocess.run(
        ["python3", validator, index_path],
        capture_output=True,
        check=False,
        text=True,
    )

    assert valid_result.returncode == 0
    assert "PASS documentops phase323 validated closure receipt summary handoff sign-off closure index validated" in (
        valid_result.stdout
    )
    assert "closure_index_valid=true" in valid_result.stdout
    assert "source_artifact_count=5" in valid_result.stdout
    assert "probe_count=5" in valid_result.stdout
    assert (
        "temporary_summary_readiness=pending_phase318_validated_closure_receipt_summary_handoff_signoff_review_no_training_authorization"
        in valid_result.stdout
    )
    assert "temporary_summary_validation_ok=true" in valid_result.stdout
    assert "service_operation_state=freeze_preserved" in valid_result.stdout
    assert "recommended_decision=keep_service_frozen" in valid_result.stdout
    assert "aws_cost_boundary=no_cost_increase" in valid_result.stdout
    assert "training_boundary=not_authorized" in valid_result.stdout

    broken = json.load(open(index_path, encoding="utf-8"))
    broken["closure_boundary"]["service_resume_authorized"] = True
    broken_path = tmp_path / "phase323_broken_resume_index.json"
    broken_path.write_text(json.dumps(broken, ensure_ascii=False, indent=2), encoding="utf-8")
    broken_result = subprocess.run(
        ["python3", validator, str(broken_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert broken_result.returncode == 1
    assert "FAIL documentops phase323 validated closure receipt summary handoff sign-off closure index validation failed" in (
        broken_result.stdout
    )
    assert "closure_boundary.service_resume_authorized must be false" in broken_result.stdout

    broken_hash = json.load(open(index_path, encoding="utf-8"))
    broken_hash["source_artifacts"][0]["sha256"] = "0" * 64
    broken_hash_path = tmp_path / "phase323_broken_hash_index.json"
    broken_hash_path.write_text(json.dumps(broken_hash, ensure_ascii=False, indent=2), encoding="utf-8")
    broken_hash_result = subprocess.run(
        ["python3", validator, str(broken_hash_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert broken_hash_result.returncode == 1
    assert "source_artifacts.phase318_validated_closure_receipt_summary_handoff.sha256 must match" in (
        broken_hash_result.stdout
    )


