def test_phase354_local_feature_completion_validated_closure_receipt_summary_handoff_validator_accepts_package_and_rejects_boundary_break(
    tmp_path,
):
    validator = "scripts/validate_documentops_phase353_validated_closure_receipt_summary_handoff.py"
    handoff_path = (
        "docs/specs/hermes_decisiondoc_agent/"
        "phase354_local_feature_completion_validated_closure_receipt_summary_handoff/"
        "validated_closure_receipt_summary_handoff.json"
    )

    result = subprocess.run(
        ["python3", validator],
        capture_output=True,
        check=False,
        text=True,
    )

    assert result.returncode == 0
    assert "PASS documentops phase354 validated closure receipt summary handoff validated" in result.stdout
    assert "phase352_validated_closure_receipt_summary_handoff_valid=true" in result.stdout
    assert "handoff_action_count=6" in result.stdout
