    assert summary["report_type"] == (
        "document_ops_phase357_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_summary"
    )
    assert summary["schema_version"] == (
        "decisiondoc_documentops_phase355_validated_closure_receipt_summary_handoff_signoff_summary.v1"
    )
    assert summary["ok"] is True
    assert summary["completion_ready"] is False
    assert summary["readiness"]["status"] == (
        "pending_phase354_validated_closure_receipt_summary_handoff_signoff_review_no_training_authorization"
    )
