    signoff_id = (
        "documentops_local_feature_completion_phase363_validated_closure_receipt_summary_handoff_signoff_summary366"
    )

    generated = subprocess.run(
        [
            "python3",
            generator,
            "--output",
            str(output_path),
            "--signoff-id",
            signoff_id,
            "--created-at",
            "2026-06-15T00:00:00+09:00",
        ],
        capture_output=True,
        check=False,
        text=True,
    )
    assert generated.returncode == 0

    summarized = subprocess.run(
        [
            "python3",
            reporter,
            str(output_path),
            "--generated-at",
            "2026-06-15T00:00:00+09:00",
            "--output",
            str(summary_path),
            "--markdown-output",
            str(markdown_path),
        ],
        capture_output=True,
        check=False,
        text=True,
    )
    summary = json.loads(summarized.stdout)
    assert summarized.returncode == 0
    assert summary["report_type"] == (
        "document_ops_phase366_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_summary"
    )
    assert summary["schema_version"] == (
        "decisiondoc_documentops_phase364_validated_closure_receipt_summary_handoff_signoff_summary.v1"
    )
    assert summary["ok"] is True
    assert summary["completion_ready"] is False
    assert summary["readiness"]["status"] == (
        "pending_phase363_validated_closure_receipt_summary_handoff_signoff_review_no_training_authorization"
    )
    assert summary["counts"]["signoff_count"] == 1
    assert summary["counts"]["valid_signoff_count"] == 1
    assert summary["counts"]["pending_signoff_count"] == 1
    assert summary["counts"]["completed_signoff_count"] == 0
    assert summary["counts"]["accepted_signoff_count"] == 0
    assert summary["counts"]["boundary_break_count"] == 0
    assert summary["signoffs"][0]["signoff_id"] == signoff_id
    assert summary["signoffs"][0]["decision"] == "pending"
