def test_phase385_local_feature_completion_validated_closure_receipt_summary_handoff_signoff_summary_validator_accepts_summary_and_rejects_boundary_breaks(
    tmp_path,
):
    generator = (
        "scripts/create_documentops_phase382_validated_closure_receipt_summary_handoff_signoff_pending_signoff.py"
    )
    reporter = "scripts/summarize_documentops_phase382_validated_closure_receipt_summary_handoff_signoffs.py"
    validator = "scripts/validate_documentops_phase384_validated_closure_receipt_summary_handoff_signoff_summary.py"
    pending_path = tmp_path / "phase383_pending_signoff.json"
    summary_path = tmp_path / "phase384_summary.json"
    signoff_id = (
        "documentops_local_feature_completion_phase381_validated_closure_receipt_summary_handoff_signoff_testpending385"
    )

    generated = subprocess.run(
        [
            "python3",
            generator,
            "--output",
            str(pending_path),
            "--signoff-id",
            signoff_id,
            "--created-at",
            "2026-06-15T00:00:00+09:00",
        ],
        capture_output=True,
        check=False,
        text=True,
    )
    assert generated.returncode == 0

    summarized = subprocess.run(
        [
            "python3",
            reporter,
            str(pending_path),
            "--generated-at",
            "2026-06-15T00:00:00+09:00",
            "--output",
            str(summary_path),
        ],
        capture_output=True,
        check=False,
        text=True,
    )
    assert summarized.returncode == 0

    valid_result = subprocess.run(
        ["python3", validator, str(summary_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert valid_result.returncode == 0
    assert "PASS documentops phase385 validated closure receipt summary handoff sign-off summary validated" in (
        valid_result.stdout
    )
    assert "signoff_summary_valid=true" in valid_result.stdout
    assert "completion_ready=false" in valid_result.stdout
    assert (
        "readiness_status=pending_phase381_validated_closure_receipt_summary_handoff_signoff_review_no_training_authorization"
        in valid_result.stdout
    )
    assert "signoff_count=1" in valid_result.stdout
    assert "service_operation_state=freeze_preserved" in valid_result.stdout
    assert "aws_cost_boundary=no_cost_increase" in valid_result.stdout
    assert "training_boundary=not_authorized" in valid_result.stdout

    require_complete = subprocess.run(
        ["python3", validator, str(summary_path), "--require-complete"],
        capture_output=True,
        check=False,
        text=True,
    )
    assert require_complete.returncode == 1
    assert "completion_ready must be true when --require-complete is used" in require_complete.stdout

    broken = json.load(open(summary_path, encoding="utf-8"))
    broken["readiness"]["training_execution_authorized"] = True
    broken_path = tmp_path / "phase385_broken_training_summary.json"
    broken_path.write_text(json.dumps(broken, ensure_ascii=False, indent=2), encoding="utf-8")
    broken_result = subprocess.run(
        ["python3", validator, str(broken_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert broken_result.returncode == 1
    assert "FAIL documentops phase385 validated closure receipt summary handoff sign-off summary validation failed" in (
        broken_result.stdout
    )
    assert "readiness.training_execution_authorized must be false" in broken_result.stdout

    broken_hash = json.load(open(summary_path, encoding="utf-8"))
    broken_hash["signoffs"][0]["sha256"] = "0" * 64
    broken_hash_path = tmp_path / "phase385_broken_signoff_hash_summary.json"
    broken_hash_path.write_text(json.dumps(broken_hash, ensure_ascii=False, indent=2), encoding="utf-8")
    broken_hash_result = subprocess.run(
        ["python3", validator, str(broken_hash_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert broken_hash_result.returncode == 1
    assert "signoffs[1].sha256 must match linked Phase 382 sign-off file" in broken_hash_result.stdout


