def test_phase43_local_export_openability_validator_accepts_ready_evidence_and_rejects_cost_boundary_break(
    tmp_path,
):
    evidence_path = (
        "docs/specs/hermes_decisiondoc_agent/"
        "phase43_local_export_openability_evidence/local_export_openability_evidence.json"
    )
    validator = "scripts/validate_phase43_local_export_openability_evidence.py"

    valid = subprocess.run(
        ["python3", validator, evidence_path],
        capture_output=True,
        check=False,
        text=True,
    )

    assert valid.returncode == 0
    assert "PASS phase43 local export openability evidence validated" in valid.stdout
    assert "local_export_openability_valid=true" in valid.stdout
    assert "pdf_opened=true" in valid.stdout
    assert "pptx_opened=true" in valid.stdout
    assert "hwp_opened=true" in valid.stdout
    assert "report_workflow_pptx_opened=true" in valid.stdout
    assert "aws_cost_boundary=no_cost_increase" in valid.stdout
    assert "training_boundary=not_authorized" in valid.stdout

    broken_payload = json.load(open(evidence_path, encoding="utf-8"))
    broken_payload["restricted_side_effect_boundary"]["aws_runtime_called"] = True
    broken_path = tmp_path / "broken_phase43_local_export_openability_evidence.json"
    broken_path.write_text(json.dumps(broken_payload, ensure_ascii=False, indent=2), encoding="utf-8")
    broken = subprocess.run(
        ["python3", validator, str(broken_path)],
        capture_output=True,
        check=False,
        text=True,
    )

    assert broken.returncode == 1
    assert "FAIL phase43 local export openability evidence validation failed" in broken.stdout
    assert "restricted_side_effect_boundary.aws_runtime_called must be false" in broken.stdout
    assert (
        "phase43_local_export_openability_evidence: "
        "$.restricted_side_effect_boundary.aws_runtime_called must be false"
        in broken.stdout
    )


